int read_sector(struct block_device *bdev, sector_t sector)
{
	char *pszBuffer;
	int iRetCode;
	size_t nBytesRead;

	pszBuffer = kmalloc(512, GFP_KERNEL);
	if (!pszBuffer)
		return -ENOMEM;
	iRetCode = submit_bio_read(bdev, sector, pszBuffer, &nBytesRead);
	kfree(pszBuffer);
	return iRetCode;
}
